import { GomokuPlayerType } from '@kyokuya/react-game-gomoku-core'
import type { IPlayer } from '../../types'
import { BasePlayer } from './BasePlayer'

export class HumanPlayer extends BasePlayer implements IPlayer {
  public readonly type = GomokuPlayerType.HUMAN
  protected r = -1
  protected c = -1

  public override init(): void {
    this.r = -1
    this.c = -1
  }

  public override move(): [r: number, c: number] {
    const { r, c } = this
    if (r >= 0) {
      this.r = -1
      this.c = -1
      return [r, c]
    }
    return [-1, -1]
  }

  public override forward(): void {}

  public override rollback(): void {}

  public override onUserInputChange(r: number, c: number): void {
    this.r = r
    this.c = c
  }
}
