import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import type { IGomokuInstruction } from '../types'
import { runInstructs } from '../util/instruction'
import { checkCompleted } from '../util/status'

export interface IGomokuState {
  /**
   * Gomoku size, sqrt of the number of vertical lines or horizontal lines.
   */
  GOMOKU_SIZE: number
  /**
   * Total players.
   */
  TOTAL_PLAYERS: number
  /**
   * Game status.
   */
  gameStatus: GameRunningStatus
  /**
   * Who win the games. -1 represents game not finished or it is a tie.
   */
  winner: number
  /**
   * The player who made the last move.
   */
  previousPlayerId: number
  /**
   * The player who currently needs to make a move.
   */
  currentPlayerId: number
  /**
   * The pieces on the gomoku board.
   */
  pieces: ReadonlyArray<IGomokuPiece>
  /**
   * Player instructions.
   */
  instructions: ReadonlyArray<IGomokuInstruction>
  /**
   * Currently activated board cell.
   */
  activatedCell: Readonly<{ r: number; c: number }> | null
  /**
   * The coordinate of the board cell for hint.
   */
  hintCell: Readonly<IGomokuPiece> | null
  /**
   * Used to judge if the game has restarted.
   */
  gameTick: number
  /**
   * Times of attempt on the current game.
   */
  attemptTick: number
  /**
   * To retrigger the hint animation when the multiple times hint requests on a
   * same cell were fired.
   */
  hintTick: number
}

export const initGomokuState = (initialState?: Partial<IGomokuState>): IGomokuState => {
  const {
    GOMOKU_SIZE = 15,
    winner = -1,
    instructions = [],
    activatedCell = null,
    gameTick = 0,
  } = { ...initialState }

  const TOTAL_PLAYERS = 2
  const pieces = runInstructs(instructions)
  const previousPlayerId: number = pieces.length <= 0 ? -1 : (pieces.length - 1) % TOTAL_PLAYERS
  const currentPlayerId: number = (previousPlayerId + 1) % TOTAL_PLAYERS
  const gameStatus: GameRunningStatus = checkCompleted(pieces, GOMOKU_SIZE, GOMOKU_SIZE)
    ? GameRunningStatus.FINISHED
    : instructions.length > 0
    ? GameRunningStatus.PAUSED
    : GameRunningStatus.PENDING

  return {
    GOMOKU_SIZE,
    TOTAL_PLAYERS,
    gameStatus,
    winner,
    previousPlayerId,
    currentPlayerId,
    pieces,
    instructions,
    activatedCell,
    hintCell: null,
    gameTick,
    attemptTick: 0,
    hintTick: 0,
  }
}
