import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import { GomokuContext, leftHalfGomokuDirectionTypes } from '@algorithm.ts/gomoku'

/**
 * Check if the game completed.
 *
 * @param pieces
 * @param MAX_ROW
 * @param MAX_COL
 * @param MAX_INLINE
 * @returns
 */
export function checkCompleted(
  pieces: ReadonlyArray<IGomokuPiece>,
  MAX_ROW: number,
  MAX_COL: number,
  MAX_INLINE = 5,
): boolean {
  const context = new GomokuContext(MAX_ROW, MAX_COL, MAX_INLINE)
  const THRESHOLD: number = context.MAX_INLINE - 1

  const board = new Int32Array(context.TOTAL_POS).fill(-1)
  for (const { r, c, p } of pieces) {
    const id: number = context.idx(r, c)
    board[id] = p
  }

  for (const dirType of leftHalfGomokuDirectionTypes) {
    for (let id = 0; id < context.TOTAL_POS; ++id) {
      if (context.maxMovableSteps(id, dirType) < THRESHOLD) continue

      const player: number = board[id]
      if (player < 0) continue

      let flag = true
      for (let step = 0, id2 = id; step < THRESHOLD; ++step) {
        id2 = context.fastMoveOneStep(id2, dirType)
        if (board[id2] !== player) {
          flag = false
          break
        }
      }
      if (flag) {
        return true
      }
    }
  }
  return false
}
